const source = $('Workflow Input Trigger').all()[0].json;
const promptTemplate = $('Load Chapter Task Prompt').item.json.content;
const schema = $json.schema || $json;
const chapterIndex = Number(source.chapter_index || source.chapterIndex || 1);
const chapterNo = String(chapterIndex).padStart(3, '0');
const chapterPlan = source.chapter_plan || source.chapterPlan || (source.outline_20?.chapters || []).find(ch => Number(ch.chapter_index) === chapterIndex);
if (!chapterPlan) throw new Error('chapter_plan is required for chapter ' + chapterIndex);
const stateMemory = source.state_memory || source.stateMemory || {};
const payload = {
  story_bible: source.story_bible_markdown || source.story_bible || '',
  chapter_plan: chapterPlan,
  recent_summaries: source.recent_summaries || [],
  state_memory: stateMemory,
  active_foreshadowing: source.active_foreshadowing || []
};
const prompt = `${promptTemplate}

请基于以下输入生成第 ${chapterIndex} 章任务单。
输入：
${JSON.stringify(payload, null, 2)}

必须严格符合以下 JSON Schema，只输出 JSON，不要输出 Markdown 或解释：
${JSON.stringify(schema, null, 2)}`;
return [{ json: {
  ...source,
  chapter_index: chapterIndex,
  chapter_no: chapterNo,
  chapter_plan: chapterPlan,
  state_memory: stateMemory,
  story_bible_markdown: source.story_bible_markdown || source.story_bible || '',
  chapter_task_path: `chapter_tasks/ch${chapterNo}.task.json`,
  scene_cards_path: `scenes/ch${chapterNo}.scenes.json`,
  chapter_path: `chapters/ch${chapterNo}.md`,
  qa_path: `review/ch${chapterNo}.qa.json`,
  memory_path: `memory/ch${chapterNo}.memory.json`,
  prompt
} }];

function extractContent(response) {
  if (typeof response === 'string') {
    try { response = JSON.parse(response); } catch (err) { response = { data: response }; }
  }
  if (typeof response.data === 'string') {
    try { response = JSON.parse(response.data); } catch (err) {}
  }
  if (response.body && typeof response.body === 'string') {
    try { response = JSON.parse(response.body); } catch (err) {}
  }
  return response.choices?.[0]?.message?.content
    || response.content?.[0]?.text
    || response.output_text
    || response.text
    || response.data?.choices?.[0]?.message?.content
    || '';
}
function parseJsonFromText(raw, label) {
  let txt = String(raw).trim();
  if (txt.startsWith('```')) txt = txt.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  const s = txt.indexOf('{');
  const e = txt.lastIndexOf('}');
  if (s !== -1 && e !== -1 && e > s) txt = txt.slice(s, e + 1);
  try { return JSON.parse(txt); } catch (err) { throw new Error(label + ' JSON parse failed: ' + raw); }
}
